INSERT INTO questions (subject_id, question, answer, order_index) VALUES
  ('a1000000-0000-0000-0000-000000000001', 'Define the Laplace Transform and state its linearity property.', 'The Laplace Transform of a function f(t), defined for t ≥ 0, is given by L{f(t)} = F(s) = ∫₀^∞ e^(-st) f(t) dt, where s is a complex number. The linearity property states that L{af(t) + bg(t)} = aF(s) + bG(s), where a and b are constants.', 1),
  ('a1000000-0000-0000-0000-000000000001', 'Find the Laplace Transform of e^(at) and sin(bt).', 'L{e^(at)} = 1/(s-a) for s > a. L{sin(bt)} = b/(s² + b²) for s > 0. These are fundamental transforms used extensively in solving differential equations.', 2),
  ('a1000000-0000-0000-0000-000000000001', 'State and prove the First Shifting Theorem.', 'First Shifting Theorem: If L{f(t)} = F(s), then L{e^(at)f(t)} = F(s-a). Proof: L{e^(at)f(t)} = ∫₀^∞ e^(-st) e^(at) f(t) dt = ∫₀^∞ e^(-(s-a)t) f(t) dt = F(s-a).', 3),
  ('a1000000-0000-0000-0000-000000000001', 'Explain Inverse Laplace Transform with examples.', 'The Inverse Laplace Transform recovers f(t) from F(s): L⁻¹{F(s)} = f(t). Examples: L⁻¹{1/(s-a)} = e^(at), L⁻¹{b/(s²+b²)} = sin(bt), L⁻¹{s/(s²+b²)} = cos(bt).', 4),
  ('a1000000-0000-0000-0000-000000000001', 'Solve the differential equation y'' + 4y = sin(2t) using Laplace Transform.', 'Taking Laplace Transform: s²Y(s) - sy(0) - y''(0) + 4Y(s) = 2/(s²+4). With y(0)=0, y''(0)=0: Y(s)(s²+4) = 2/(s²+4), so Y(s) = 2/(s²+4)². Using convolution or partial fractions: y(t) = (1/4)(sin(2t) - 2t·cos(2t)).', 5);
INSERT INTO questions (subject_id, question, answer, order_index) VALUES
  ('a1000000-0000-0000-0000-000000000002', 'State Gauss''s Law and derive the electric field due to an infinite plane sheet of charge.', 'Gauss''s Law: ∮ E⃗·dA⃗ = Q_enc/ε₀. For an infinite plane sheet with surface charge density σ, using a cylindrical Gaussian surface: 2EA = σA/ε₀, giving E = σ/(2ε₀) directed perpendicular to the surface.', 1),
  ('a1000000-0000-0000-0000-000000000002', 'Explain Faraday''s Law of electromagnetic induction.', 'Faraday''s Law states that the induced EMF in a closed circuit is equal to the negative rate of change of magnetic flux through the circuit: EMF = -dΦ_B/dt, where Φ_B = ∫ B⃗·dA⃗. This is the basis of electromagnetic induction.', 2),
  ('a1000000-0000-0000-0000-000000000002', 'Derive the de Broglie wavelength and explain wave-particle duality.', 'de Broglie proposed that matter has wave properties: λ = h/p = h/(mv), where h is Planck''s constant. Wave-particle duality means that all matter exhibits both wave and particle properties. For electrons: λ = h/√(2mE_k).', 3),
  ('a1000000-0000-0000-0000-000000000002', 'Explain the photoelectric effect and Einstein''s equation.', 'When light strikes a metal surface, electrons are emitted if the frequency exceeds a threshold. Einstein''s equation: E_k(max) = hν - φ, where hν is photon energy and φ is the work function. This proved the quantum nature of light.', 4),
  ('a1000000-0000-0000-0000-000000000002', 'Describe Maxwell''s equations in differential form.', '1. ∇·E⃗ = ρ/ε₀ (Gauss), 2. ∇·B⃗ = 0 (No monopoles), 3. ∇×E⃗ = -∂B⃗/∂t (Faraday), 4. ∇×B⃗ = μ₀J⃗ + μ₀ε₀∂E⃗/∂t (Ampère-Maxwell). These four equations completely describe classical electromagnetism.', 5);
INSERT INTO questions (subject_id, question, answer, order_index) VALUES
  ('a1000000-0000-0000-0000-000000000003', 'Explain the mechanism of electrochemical corrosion.', 'Electrochemical corrosion involves the formation of galvanic cells on the metal surface. At the anode: M → M^n+ + ne⁻ (oxidation/dissolution). At the cathode: O₂ + 2H₂O + 4e⁻ → 4OH⁻ (in neutral/alkaline) or 2H⁺ + 2e⁻ → H₂ (in acidic). The metal acts as both anode and cathode.', 1),
  ('a1000000-0000-0000-0000-000000000003', 'Describe the process of electroplating with a suitable example.', 'Electroplating deposits a thin layer of metal on an object using electrolysis. Example: Chrome plating - Object = cathode, CrO₃ solution = electrolyte. Cr⁶⁺ ions are reduced at cathode: Cr⁶⁺ + 6e⁻ → Cr. Factors: current density, temperature, concentration, and additives.', 2),
  ('a1000000-0000-0000-0000-000000000003', 'Explain the construction and working of a lithium-ion battery.', 'A Li-ion battery consists of: Anode (graphite, LiC₆), Cathode (LiCoO₂), and organic electrolyte with Li salt. During discharge: Li⁺ ions move from anode to cathode through electrolyte. Charging reverses this. Cell voltage: ~3.7V. High energy density, low self-discharge.', 3),
  ('a1000000-0000-0000-0000-000000000003', 'What are conducting polymers? Explain with examples.', 'Conducting polymers are organic polymers that conduct electricity. Examples: Polyacetylene, Polyaniline (PANI), Polypyrrole. Conductivity arises from conjugated π-electron systems. Doping (oxidation/reduction) increases conductivity from insulator to metallic range (10⁻¹⁰ to 10⁵ S/cm).', 4),
  ('a1000000-0000-0000-0000-000000000003', 'Explain the phase rule and its application to the water system.', 'Gibbs Phase Rule: F = C - P + 2, where F = degrees of freedom, C = components, P = phases. For water (C=1): At triple point (P=3): F=0 (invariant). Along curves (P=2): F=1 (univariant). In regions (P=1): F=2 (bivariant).', 5);
INSERT INTO questions (subject_id, question, answer, order_index) VALUES
  ('a1000000-0000-0000-0000-000000000004', 'Explain the concept of recursion with the Tower of Hanoi problem.', 'Recursion is a technique where a function calls itself. Tower of Hanoi: Move n disks from source to destination using auxiliary peg. Algorithm: 1) Move n-1 disks from source to auxiliary, 2) Move nth disk from source to destination, 3) Move n-1 disks from auxiliary to destination. Time complexity: O(2ⁿ).', 1),
  ('a1000000-0000-0000-0000-000000000004', 'Compare and contrast linear search and binary search algorithms.', 'Linear Search: Sequentially checks each element. Time: O(n). Works on unsorted arrays. Binary Search: Divides search interval in half repeatedly. Time: O(log n). Requires sorted array. Binary search is exponentially faster for large datasets.', 2),
  ('a1000000-0000-0000-0000-000000000004', 'Explain sorting algorithms: Bubble Sort vs Quick Sort.', 'Bubble Sort: Repeatedly swaps adjacent elements if in wrong order. Time: O(n²) avg/worst. Space: O(1). Stable. Quick Sort: Picks pivot, partitions array, recursively sorts. Time: O(n log n) avg, O(n²) worst. Space: O(log n). Not stable. Quick Sort is preferred for large datasets.', 3),
  ('a1000000-0000-0000-0000-000000000004', 'Explain linked lists and their types with operations.', 'Linked List: Linear data structure where elements (nodes) contain data and pointer to next node. Types: Singly (next only), Doubly (next + prev), Circular (last points to first). Operations: Insert (O(1) at head), Delete (O(1) at head), Search (O(n)), Traverse (O(n)).', 4),
  ('a1000000-0000-0000-0000-000000000004', 'Describe stack and queue data structures with real-world applications.', 'Stack: LIFO (Last In First Out). Operations: push, pop, peek. Applications: function calls, undo operations, expression evaluation. Queue: FIFO (First In First Out). Operations: enqueue, dequeue, front. Applications: scheduling, BFS, print queue. Both have O(1) for insert/delete.', 5);
INSERT INTO questions (subject_id, question, answer, order_index) VALUES
  ('a1000000-0000-0000-0000-000000000005', 'Explain Boolean algebra and its fundamental theorems.', 'Boolean algebra deals with binary variables (0,1) and logic operations (AND, OR, NOT). Fundamental theorems: Identity (A+0=A, A·1=A), Complement (A+A''=1, A·A''=0), De Morgan''s (A+B)'' = A''·B'' and (A·B)'' = A''+B''. Used in digital circuit design.', 1),
  ('a1000000-0000-0000-0000-000000000005', 'Design a full adder circuit and explain its working.', 'Full Adder adds three bits (A, B, Cin) producing Sum and Carry. Sum = A⊕B⊕Cin, Cout = AB + BCin + ACin. Can be built from two half adders and an OR gate. Truth table has 8 rows (2³ combinations).', 2),
  ('a1000000-0000-0000-0000-000000000005', 'Explain flip-flops: SR, JK, D, and T types.', 'SR: Set-Reset, invalid when S=R=1. JK: Universal flip-flop, toggles when J=K=1. D: Data flip-flop, Q follows D on clock edge. T: Toggle flip-flop, toggles on T=1. All are sequential circuits with memory capability.', 3),
  ('a1000000-0000-0000-0000-000000000005', 'Describe the architecture of an 8-bit microprocessor.', 'An 8-bit microprocessor (e.g., 8085) contains: ALU (arithmetic/logic), Accumulator (8-bit register), General registers (B,C,D,E,H,L), Program Counter (16-bit), Stack Pointer (16-bit), Instruction Register, Control Unit. It processes 8 bits of data per operation.', 4),
  ('a1000000-0000-0000-0000-000000000005', 'Explain the concept of multiplexers and demultiplexers.', 'Multiplexer (MUX): Selects one of many inputs and forwards to single output. 4:1 MUX has 4 inputs, 2 select lines, 1 output. Demultiplexer (DEMUX): Routes single input to one of many outputs. Used in data routing, communication systems, and memory addressing.', 5);
INSERT INTO questions (subject_id, question, answer, order_index) VALUES
  ('a1000000-0000-0000-0000-000000000006', 'Discuss the contribution of ancient Tamils to metallurgy.', 'Ancient Tamils were pioneers in iron and steel technology. The Wootz steel (Ukku) was produced in Tamil Nadu and exported globally. Sangam literature references iron smelting. The Kodumanal archaeological site reveals advanced metallurgical practices dating to 300 BCE.', 1),
  ('a1000000-0000-0000-0000-000000000006', 'Explain the irrigation systems developed by ancient Tamils.', 'Ancient Tamils developed sophisticated irrigation: Kallanai (Grand Anicut) built by Karikala Chola (~2nd century CE) on the Kaveri River is one of the oldest water-diversion structures still in use. They built tanks (Eri), channels, and sluice systems for agriculture.', 2),
  ('a1000000-0000-0000-0000-000000000006', 'Describe the maritime technology and trade of ancient Tamils.', 'Tamils were master seafarers. Sangam texts describe ship-building (Kalam), navigation using stars. They traded with Rome, Southeast Asia, and China. Musiri was a major port. Items traded: pepper, pearls, textiles. Evidence: Roman coins found in Tamil Nadu.', 3),
  ('a1000000-0000-0000-0000-000000000006', 'Explain the role of Tamil in computing and digital technology.', 'Tamil was one of the first Indian languages to have Unicode support (Tamil Unicode block: U+0B80-U+0BFF). Tamil99 keyboard layout is standard. INFITT (International Forum for Information Technology in Tamil) promotes Tamil computing. Tamil NLP research is growing rapidly.', 4),
  ('a1000000-0000-0000-0000-000000000006', 'Discuss the architectural achievements of Tamil civilizations.', 'Tamil temple architecture evolved through Pallava (rock-cut: Mahabalipuram), Chola (structural: Brihadeeswarar Temple), and Pandya periods. Features: Dravidian style, gopurams, vimanas. The Brihadeeswarar Temple (1010 CE) uses an 80-ton capstone lifted without modern machinery.', 5);
INSERT INTO questions (subject_id, question, answer, order_index) VALUES
  ('a1000000-0000-0000-0000-000000000008', 'Explain the working principle of a PN junction diode.', 'A PN junction forms when P-type (holes majority) and N-type (electrons majority) semiconductors join. Depletion region forms at junction. Forward bias (P→+, N→-): reduces barrier, current flows. Reverse bias: widens depletion region, minimal current. Used in rectification.', 1),
  ('a1000000-0000-0000-0000-000000000008', 'Describe the characteristics and applications of BJT.', 'BJT (Bipolar Junction Transistor): Three terminals - Base, Collector, Emitter. Types: NPN and PNP. Regions: Active (amplification), Saturation (switch ON), Cutoff (switch OFF). Current gain: β = I_C/I_B. Applications: amplifiers, switches, oscillators.', 2),
  ('a1000000-0000-0000-0000-000000000008', 'Explain operational amplifier characteristics and applications.', 'Op-Amp: High gain differential amplifier. Ideal characteristics: infinite gain, infinite input impedance, zero output impedance, infinite bandwidth. Applications: Inverting amplifier (gain=-Rf/Ri), Non-inverting (gain=1+Rf/Ri), Summing amplifier, Integrator, Differentiator.', 3),
  ('a1000000-0000-0000-0000-000000000008', 'Compare MOSFET and JFET transistors.', 'JFET: Voltage-controlled, depletion mode only, gate is reverse-biased PN junction. MOSFET: Voltage-controlled, enhancement and depletion modes, gate insulated by oxide layer. MOSFET advantages: higher input impedance, easier fabrication, used in CMOS logic.', 4),
  ('a1000000-0000-0000-0000-000000000008', 'Explain rectifier circuits: half-wave and full-wave.', 'Half-wave: Uses single diode, conducts only positive half cycles. Efficiency: 40.6%, ripple factor: 1.21. Full-wave (bridge): Uses 4 diodes, conducts both halves. Efficiency: 81.2%, ripple factor: 0.48. Filter capacitor smooths output DC.', 5);
